let AnalyticTables = dynamic([{AnalyticTierTables}]);
let DataLakeTables = dynamic([{DataLakeTierTables}]);
let Days = datetime_diff('day', {TimeRange:end}, {TimeRange:start});
Usage
| where TimeGenerated {TimeRange}
| where IsBillable == true
| summarize TotalMB = sum(Quantity) by DataType
| extend DailyAvgGB = TotalMB / 1000.0 / Days
| extend Tier = case(
    DataType in (AnalyticTables), 'Analytic',
    DataType in (DataLakeTables), 'Data Lake',
    'Defender XDR Only')
| summarize GBperDay = round(sum(DailyAvgGB), 2) by Tier

let AnalyticCost = toreal('{AnalyticCostPerGB}');
let DLIngestionCost = toreal('{DataLakeIngestionCostPerGB}');
let DLStorageCost = toreal('{DataLakeStorageCostPerGB}');
let DLRetentionMonths = toreal('{DataLakeRetentionMonths}');
let CompressionRatio = 6.0;
let AnalyticTables = dynamic([{AnalyticTierTables}]);
let DataLakeTables = dynamic([{DataLakeTierTables}]);
let Days = datetime_diff('day', {TimeRange:end}, {TimeRange:start});
Usage
| where TimeGenerated {TimeRange}
| where IsBillable == true
| summarize TotalMB = sum(Quantity) by DataType
| extend DailyAvgGB = TotalMB / 1000.0 / Days
| extend Tier = case(
    DataType in (AnalyticTables), 'Analytic',
    DataType in (DataLakeTables), 'DataLake',
    'XDROnly')
| where Tier != 'Analytic'
| extend Savings = round(DailyAvgGB * 30 * AnalyticCost - case(
    Tier == 'DataLake', (DailyAvgGB * 30 * DLIngestionCost) + (DailyAvgGB * 30 * DLRetentionMonths / CompressionRatio * DLStorageCost),
    0.0), 2)
| top 15 by Savings desc
| project DataType, Savings

let AnalyticCost = toreal('{AnalyticCostPerGB}');
let DLIngestionCost = toreal('{DataLakeIngestionCostPerGB}');
let DLStorageCost = toreal('{DataLakeStorageCostPerGB}');
let DLRetentionMonths = toreal('{DataLakeRetentionMonths}');
let CompressionRatio = 6.0;
let AnalyticTables = dynamic([{AnalyticTierTables}]);
let DataLakeTables = dynamic([{DataLakeTierTables}]);
Usage
| where TimeGenerated {TimeRange}
| where IsBillable == true
| summarize TotalMB = sum(Quantity) by bin(StartTime, 1d), DataType
| extend
    DailyGB = TotalMB / 1000.0,
    Tier = case(
        DataType in (AnalyticTables), 'Analytic',
        DataType in (DataLakeTables), 'DataLake',
        'XDROnly')
| summarize
    CurrentCost = round(sum(DailyGB) * AnalyticCost, 2),
    OptimizedCost = round(
        sumif(DailyGB, Tier == 'Analytic') * AnalyticCost +
        sumif(DailyGB, Tier == 'DataLake') * DLIngestionCost +
        sumif(DailyGB, Tier == 'DataLake') * DLRetentionMonths / CompressionRatio * DLStorageCost, 2)
    by bin(StartTime, 1d)
| extend DailySavings = round(CurrentCost - OptimizedCost, 2)
| order by StartTime asc
